63	error_t ec_pve_ac_t::encrypt_row1(const pve_base_pke_i& base_pke, const ss::ac_t& ac, const pks_t& ac_pks, mem_t L,
64	                                  ecurve_t curve, mem_t r1, mem_t x1_bin, buf_t& c1,
65	                                  std::vector<ciphertext_adapter_t>& quorum_c1) const {
66	  return encrypt_row(base_pke, ac, ac_pks, L, curve,
67	                     r1,        // seed
68	                     x1_bin,    // plain
69	                     c1,        // output
70	                     quorum_c1  // output
