74	error_t ec_pve_ac_t::encrypt(const pve_base_pke_i& base_pke, const ss::ac_t& ac, const pks_t& ac_pks, mem_t label,
75	                             ecurve_t curve, const std::vector<bn_t>& _x) {
76	  error_t rv = UNINITIALIZED_ERROR;
77	  int batch_size = int(_x.size());
78	  const auto& G = curve.generator();
79	  const mod_t& q = curve.order();
80	
81	  std::vector<bn_t> x(batch_size);
82	  Q.resize(batch_size);
83	  for (int i = 0; i < batch_size; i++) {
84	    x[i] = _x[i] % q;
85	    Q[i] = x[i] * G;
86	  }
87	  L = crypto::sha256_t::hash(label, Q);
88	
89	  std::vector<std::vector<ecc_point_t>> X0(kappa);
90	  std::vector<std::vector<ecc_point_t>> X1(kappa);
91	  std::vector<buf_t> c0(kappa);
92	  std::vector<buf_t> c1(kappa);
93	  std::vector<std::vector<ciphertext_adapter_t>> quorum_c0(kappa);
94	  std::vector<std::vector<ciphertext_adapter_t>> quorum_c1(kappa);
95	  std::vector<buf_t> r0_1(kappa);
96	  std::vector<buf_t> r0_2(kappa);
97	  std::vector<buf_t> r1(kappa);
98	
99	  for (int i = 0; i < kappa; i++) {
100	    X0[i].resize(batch_size);
101	    X1[i].resize(batch_size);
102	
103	    r0_1[i] = crypto::gen_random_bitlen(SEC_P_COM);
104	    r0_2[i] = crypto::gen_random_bitlen(SEC_P_COM);
105	    r1[i] = crypto::gen_random_bitlen(SEC_P_COM);
106	
107	    std::vector<bn_t> x0;
108	    if (rv = encrypt_row0(base_pke, ac, ac_pks, L, curve, r0_1[i], r0_2[i], batch_size, x0, c0[i], quorum_c0[i]))
109	      return rv;
110	
111	    std::vector<bn_t> x1(batch_size);
112	    for (int j = 0; j < batch_size; j++) MODULO(q) x1[j] = x[j] - x0[j];
113	
114	    row_t& row = rows[i];
115	    row.x_bin = batch_to_bin(curve, x1);
116	    if (rv = encrypt_row1(base_pke, ac, ac_pks, L, curve, r1[i], row.x_bin, c1[i], quorum_c1[i])) return rv;
117	
118	    for (int j = 0; j < batch_size; j++) {
119	      X0[i][j] = x0[j] * G;
120	      X1[i][j] = Q[j] - X0[i][j];
121	    }
122	  }
123	
124	  b = crypto::ro::hash_string(Q, label, c0, c1, quorum_c0, quorum_c1, X0, X1).bitlen(kappa);
125	
126	  for (int i = 0; i < kappa; i++) {
127	    bool bit = b.get_bit(i);
128	    rows[i].r = bit ? r1[i] : (r0_1[i] + r0_2[i]);  // concat
129	    rows[i].c = bit ? c0[i] : c1[i];
130	    rows[i].quorum_c = bit ? quorum_c0[i] : quorum_c1[i];
131	    if (!bit) rows[i].x_bin.free();  // clear output
132	  }
133	  return SUCCESS;
134	}
