136	error_t ec_pve_ac_t::verify(const pve_base_pke_i& base_pke, const ss::ac_t& ac, const pks_t& ac_pks,
137	                            const std::vector<ecc_point_t>& Q, mem_t label) const {
138	  error_t rv = UNINITIALIZED_ERROR;
139	  int batch_size = int(Q.size());
140	  if (batch_size == 0) return coinbase::error(E_BADARG);
141	
142	  ecurve_t curve = Q[0].get_curve();
143	  const auto& G = curve.generator();
144	  if (Q.size() != this->Q.size()) return coinbase::error(E_CRYPTO);
145	  for (int i = 0; i < batch_size; i++) {
146	    if (rv = curve.check(Q[i])) return coinbase::error(rv, "ec_pve_ac_t::verify: check Q[i] failed");
147	  }
148	  if (Q != this->Q) return coinbase::error(E_CRYPTO);
149	
150	  buf_t L = crypto::sha256_t::hash(label, Q);
151	  if (L != this->L) return coinbase::error(E_CRYPTO);
152	
153	  std::vector<std::vector<ecc_point_t>> X0(kappa);
154	  std::vector<std::vector<ecc_point_t>> X1(kappa);
155	  std::vector<buf_t> c0(kappa);
156	  std::vector<buf_t> c1(kappa);
157	  std::vector<std::vector<ciphertext_adapter_t>> quorum_c0(kappa);
158	  std::vector<std::vector<ciphertext_adapter_t>> quorum_c1(kappa);
159	
160	  for (int i = 0; i < kappa; i++) {
161	    X0[i].resize(batch_size);
162	    X1[i].resize(batch_size);
163	    bool bit = b.get_bit(i);
164	    const row_t& row = rows[i];
165	
166	    std::vector<bn_t> xb;
167	    if (bit) {
168	      c0[i] = row.c;
169	      quorum_c0[i] = row.quorum_c;
170	      if (rv = batch_from_bin(curve, batch_size, row.x_bin, xb)) return rv;
171	      mem_t r1 = row.r;
172	      if (rv = encrypt_row1(base_pke, ac, ac_pks, L, curve, r1, row.x_bin, c1[i], quorum_c1[i])) return rv;
173	    } else {
174	      c1[i] = row.c;
175	      quorum_c1[i] = row.quorum_c;
176	      if (row.r.size() != 32) return coinbase::error(E_CRYPTO);
177	      mem_t r0_1 = row.r.take(16);
178	      mem_t r0_2 = row.r.skip(16);
179	      if (rv = encrypt_row0(base_pke, ac, ac_pks, L, curve, r0_1, r0_2, batch_size, xb, c0[i], quorum_c0[i])) return rv;
180	    }
181	
182	    for (int j = 0; j < batch_size; j++) {
183	      ecc_point_t Xb = xb[j] * G;
184	      X1[i][j] = bit ? Xb : Q[j] - Xb;
185	      X0[i][j] = bit ? Q[j] - Xb : Xb;
186	    }
187	  }
188	
189	  buf128_t b_tag;
190	  b_tag = crypto::ro::hash_string(Q, label, c0, c1, quorum_c0, quorum_c1, X0, X1).bitlen(SEC_P_COM);
191	  if (b_tag != b) return coinbase::error(E_CRYPTO);
192	  return SUCCESS;
193	}
