231	error_t ec_pve_ac_t::aggregate_to_restore_row(const pve_base_pke_i& base_pke, const ss::ac_t& ac, int row_index,
232	                                              mem_t label, const std::map<std::string, bn_t>& quorum_decrypted,
233	                                              std::vector<bn_t>& x, bool skip_verify, const pks_t& all_ac_pks) const {
234	  error_t rv = UNINITIALIZED_ERROR;
235	  if (row_index < 0 || row_index >= kappa) return coinbase::error(E_RANGE);
236	  if (Q.empty()) return coinbase::error(E_BADARG);
237	
238	  if (!skip_verify) {
239	    if (all_ac_pks.empty()) {
240	      return coinbase::error(E_BADARG, "all_ac_pks is required when skip_verify is false");
241	    }
242	    if (rv = verify(base_pke, ac, all_ac_pks, Q, label)) return rv;
243	  }
244	
245	  const row_t& row = rows[row_index];
246	
247	  int batch_size = int(Q.size());
248	  ecurve_t curve = Q[0].get_curve();
249	  int curve_size = curve.size();
250	  const auto& G = curve.generator();
251	  const mod_t& q = curve.order();
252	
253	  buf_t L = crypto::sha256_t::hash(label, Q);
254	
255	  bn_t K;
256	  if (rv = ac.reconstruct(q, quorum_decrypted, K)) return rv;
257	
258	  buf_t k_and_iv = crypto::ro::hash_string(K, L).bitlen(256 + iv_bitlen);
259	  mem_t k_aes = k_and_iv.take(32);
260	  mem_t iv = k_and_iv.skip(32);
261	
262	  buf_t decrypted_data;
263	  if (rv = crypto::aes_gcm_t::decrypt(k_aes, iv, L, tag_size, row.c, decrypted_data)) return rv;
264	
265	  mem_t seed;
266	  mem_t x_bin;
267	
268	  bool bit = b.get_bit(row_index);
269	  if (bit) {
270	    x_bin = row.x_bin;
271	    seed = decrypted_data;
272	  } else {
273	    x_bin = decrypted_data;
274	    if (row.r.size() != 32) return coinbase::error(E_CRYPTO);
275	    seed = row.r.take(16);
276	  }
277	
278	  if (x_bin.size != batch_size * curve_size) return coinbase::error(E_CRYPTO);
279	  crypto::drbg_aes_ctr_t drbg(seed);
280	  x.resize(batch_size);
281	  for (int j = 0; j < batch_size; j++) {
282	    bn_t x0 = drbg.gen_bn(q);
283	    bn_t x1 = bn_t::from_bin(x_bin.range(j * curve_size, curve_size));
284	    MODULO(q) x[j] = x0 + x1;
285	    if (x[j] * G != Q[j]) return coinbase::error(E_CRYPTO);
286	  }
287	
288	  return SUCCESS;
289	}
