21	struct pve_ac_ciphertext_blob_v1_t {
22	  uint32_t version = pve_ac_ciphertext_version_v1;
23	  uint32_t batch_count = 0;
24	  buf_t ct;  // serialized `coinbase::mpc::ec_pve_ac_t`
25	
26	  void convert(coinbase::converter_t& c) { c.convert(version, batch_count, ct); }
27	};
