29	static error_t parse_ac_ciphertext(mem_t ciphertext, pve_ac_ciphertext_blob_v1_t& out_blob) {
30	  error_t rv = coinbase::convert(out_blob, ciphertext);
31	  if (rv) return rv;
32	  if (out_blob.version != pve_ac_ciphertext_version_v1)
33	    return coinbase::error(E_FORMAT, "unsupported ciphertext version");
34	  if (out_blob.batch_count == 0) return coinbase::error(E_FORMAT, "invalid batch count");
35	  if (out_blob.batch_count > static_cast<uint32_t>(MAX_BATCH_COUNT)) return coinbase::error(E_RANGE, "batch too large");
36	  return SUCCESS;
37	}
