39	static error_t to_internal_ac_and_leaves(const access_structure_t& ac_in, const coinbase::crypto::ecurve_t& curve,
40	                                         coinbase::crypto::ss::ac_owned_t& out_ac,
41	                                         std::set<std::string>& out_leaf_names) {
42	  out_leaf_names.clear();
43	  error_t rv = coinbase::api::detail::collect_leaf_names(ac_in, out_leaf_names);
44	  if (rv) return rv;
45	  if (out_leaf_names.empty()) return coinbase::error(E_BADARG, "access_structure: missing leaves");
46	
47	  std::vector<std::string_view> party_names;
48	  party_names.reserve(out_leaf_names.size());
49	  for (const auto& s : out_leaf_names) party_names.emplace_back(s);
50	
51	  return coinbase::api::detail::to_internal_access_structure(ac_in, party_names, curve, out_ac);
52	}
