78	static error_t validate_quorum_shares_subset(const std::set<std::string>& leaf_names, const leaf_shares_t& shares,
79	                                             const char* what) {
80	  if (shares.empty()) return coinbase::error(E_BADARG, std::string(what) + ": quorum_shares must be non-empty");
81	
82	  for (const auto& [name_view, share] : shares) {
83	    if (name_view.empty()) return coinbase::error(E_BADARG, std::string(what) + ": leaf name must be non-empty");
84	    if (share.size < 0) return coinbase::error(E_BADARG, std::string(what) + ": invalid share size");
85	    if (share.size > 0 && !share.data) return coinbase::error(E_BADARG, std::string(what) + ": missing share bytes");
86	    if (share.size > coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE)
87	      return coinbase::error(E_RANGE, std::string(what) + ": share too large");
88	    if (leaf_names.count(std::string(name_view)) == 0)
89	      return coinbase::error(E_BADARG, std::string(what) + ": unknown leaf name");
90	  }
91	  return SUCCESS;
92	}
