94	static void build_internal_leaf_key_ptrs(const leaf_keys_t& in, std::map<std::string, coinbase::mem_t>& out_key_mems,
95	                                         coinbase::mpc::ec_pve_ac_t::pks_t& out_ptrs) {
96	  out_key_mems.clear();
97	  out_ptrs.clear();
98	  for (const auto& [name_view, key] : in) {
99	    out_key_mems.emplace(std::string(name_view), coinbase::mem_t(key.data, key.size));
100	  }
101	  for (auto& [name, key_mem] : out_key_mems) out_ptrs.emplace(name, coinbase::mpc::pve_keyref(key_mem));
102	}
