158	error_t verify_ac(const base_pke_i& base_pke, curve_id curve, const access_structure_t& ac, const leaf_keys_t& ac_pks,
159	                  mem_t ciphertext, const std::vector<mem_t>& Qs_compressed, mem_t label) {
160	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
161	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
162	    return rv;
163	  if (const error_t rv = coinbase::api::detail::validate_mem_vec_arg(Qs_compressed, "Qs_compressed")) return rv;
164	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
165	  error_t rv = UNINITIALIZED_ERROR;
166	
167	  const auto icurve = to_internal_curve(curve);
168	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
169	
170	  coinbase::crypto::ss::ac_owned_t ac_internal;
171	  std::set<std::string> leaf_names;
172	  if (rv = to_internal_ac_and_leaves(ac, icurve, ac_internal, leaf_names)) return rv;
173	  if (rv = validate_leaf_keys_exact(leaf_names, ac_pks, "ac_pks")) return rv;
174	
175	  pve_ac_ciphertext_blob_v1_t blob;
176	  if (rv = parse_ac_ciphertext(ciphertext, blob)) return rv;
177	
178	  if (Qs_compressed.size() != static_cast<size_t>(blob.batch_count))
179	    return coinbase::error(E_BADARG, "Q count mismatch");
180	
181	  coinbase::mpc::ec_pve_ac_t pve_ct;
182	  if (rv = coinbase::convert(pve_ct, blob.ct)) return rv;
183	
184	  // Validate ciphertext curve.
185	  for (const auto& q : pve_ct.get_Q()) {
186	    if (q.get_curve() != icurve) return coinbase::error(E_BADARG, "ciphertext curve mismatch");
187	  }
188	
189	  std::vector<coinbase::crypto::ecc_point_t> Q_expected;
190	  Q_expected.resize(Qs_compressed.size());
191	  for (size_t i = 0; i < Qs_compressed.size(); i++) {
192	    if (rv = Q_expected[i].from_bin(icurve, Qs_compressed[i])) return coinbase::error(rv, "invalid Q");
193	    if (rv = icurve.check(Q_expected[i])) return coinbase::error(rv, "invalid Q");
194	  }
195	
196	  detail::base_pke_bridge_t bridge(base_pke);
197	
198	  std::map<std::string, coinbase::mem_t> key_mems;
199	  coinbase::mpc::ec_pve_ac_t::pks_t pk_ptrs;
200	  build_internal_leaf_key_ptrs(ac_pks, key_mems, pk_ptrs);
201	
202	  return pve_ct.verify(bridge, ac_internal, pk_ptrs, Q_expected, label);
203	}
