205	error_t verify_ac(curve_id curve, const access_structure_t& ac, const leaf_keys_t& ac_pks, mem_t ciphertext,
206	                  const std::vector<mem_t>& Qs_compressed, mem_t label) {
207	  return verify_ac(base_pke_default(), curve, ac, ac_pks, ciphertext, Qs_compressed, label);
208	}
