210	error_t partial_decrypt_ac_attempt(const base_pke_i& base_pke, curve_id curve, const access_structure_t& ac,
211	                                   mem_t ciphertext, int attempt_index, std::string_view leaf_name, mem_t dk,
212	                                   mem_t label, buf_t& out_share) {
213	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
214	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
215	    return rv;
216	  if (const error_t rv =
217	          coinbase::api::detail::validate_mem_arg_max_size(dk, "dk", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
218	    return rv;
219	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
220	  error_t rv = UNINITIALIZED_ERROR;
221	
222	  const auto icurve = to_internal_curve(curve);
223	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
224	  if (leaf_name.empty()) return coinbase::error(E_BADARG, "leaf_name must be non-empty");
225	
226	  coinbase::crypto::ss::ac_owned_t ac_internal;
227	  std::set<std::string> leaf_names;
228	  if (rv = to_internal_ac_and_leaves(ac, icurve, ac_internal, leaf_names)) return rv;
229	  if (leaf_names.count(std::string(leaf_name)) == 0) return coinbase::error(E_BADARG, "unknown leaf_name");
230	
231	  pve_ac_ciphertext_blob_v1_t blob;
232	  if (rv = parse_ac_ciphertext(ciphertext, blob)) return rv;
233	
234	  coinbase::mpc::ec_pve_ac_t pve_ct;
235	  if (rv = coinbase::convert(pve_ct, blob.ct)) return rv;
236	
237	  for (const auto& q : pve_ct.get_Q()) {
238	    if (q.get_curve() != icurve) return coinbase::error(E_BADARG, "ciphertext curve mismatch");
239	  }
240	
241	  detail::base_pke_bridge_t bridge(base_pke);
242	
243	  const coinbase::mem_t dk_mem(dk.data, dk.size);
244	  coinbase::crypto::bn_t share_bn;
245	  rv = pve_ct.party_decrypt_row(bridge, ac_internal, attempt_index, std::string(leaf_name),
246	                                coinbase::mpc::pve_keyref(dk_mem), label, share_bn);
247	  if (rv) {
248	    out_share.free();
249	    return rv;
250	  }
251	
252	  out_share = share_bn.to_bin(icurve.order().get_bin_size());
253	  return SUCCESS;
254	}
