314	error_t combine_ac(const base_pke_i& base_pke, curve_id curve, const access_structure_t& ac, mem_t ciphertext,
315	                   int attempt_index, mem_t label, const leaf_shares_t& quorum_shares, std::vector<buf_t>& out_xs) {
316	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
317	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
318	    return rv;
319	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
320	  error_t rv = UNINITIALIZED_ERROR;
321	
322	  const auto icurve = to_internal_curve(curve);
323	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
324	
325	  coinbase::crypto::ss::ac_owned_t ac_internal;
326	  std::set<std::string> leaf_names;
327	  if (rv = to_internal_ac_and_leaves(ac, icurve, ac_internal, leaf_names)) return rv;
328	  if (rv = validate_quorum_shares_subset(leaf_names, quorum_shares, "quorum_shares")) return rv;
329	
330	  pve_ac_ciphertext_blob_v1_t blob;
331	  if (rv = parse_ac_ciphertext(ciphertext, blob)) return rv;
332	
333	  coinbase::mpc::ec_pve_ac_t pve_ct;
334	  if (rv = coinbase::convert(pve_ct, blob.ct)) return rv;
335	
336	  for (const auto& q : pve_ct.get_Q()) {
337	    if (q.get_curve() != icurve) return coinbase::error(E_BADARG, "ciphertext curve mismatch");
338	  }
339	
340	  const int expected_share_size = icurve.order().get_bin_size();
341	  for (const auto& [name_view, share_bytes] : quorum_shares) {
342	    if (share_bytes.size != expected_share_size) return coinbase::error(E_BADARG, "quorum_shares: invalid share size");
343	  }
344	
345	  std::map<std::string, coinbase::crypto::bn_t> quorum_bn;
346	  for (const auto& [name_view, share_bytes] : quorum_shares) {
347	    quorum_bn.emplace(std::string(name_view), coinbase::crypto::bn_t::from_bin(share_bytes));
348	  }
349	
350	  detail::base_pke_bridge_t bridge(base_pke);
351	  coinbase::mpc::ec_pve_ac_t::pks_t pk_ptrs;
352	
353	  std::vector<coinbase::crypto::bn_t> xs_bn;
354	  rv = pve_ct.aggregate_to_restore_row(bridge, ac_internal, attempt_index, label, quorum_bn, xs_bn,
355	                                       /*skip_verify=*/true, pk_ptrs);
356	  if (rv) {
357	    out_xs.clear();
358	    return rv;
359	  }
360	
361	  std::vector<buf_t> out_local;
362	  out_local.resize(xs_bn.size());
363	  const int out_len = icurve.order().get_bin_size();
364	  for (size_t i = 0; i < xs_bn.size(); i++) out_local[i] = xs_bn[i].to_bin(out_len);
365	  out_xs = std::move(out_local);
366	  return SUCCESS;
367	}
